import heapq

class Solution:
    def resultsArray(self, queries, k):
        heap = []
        res = []
        for x, y in queries:
            d = abs(x) + abs(y)
            if len(heap) < k:
                heapq.heappush(heap, -d)
            elif -heap[0] > d:
                heapq.heapreplace(heap, -d)
            res.append(-heap[0] if len(heap) == k else -1)
        return res

