var resultsArray = function(queries, k) {
    const heap = [];
    function push(v) {
        heap.push(v);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p] < heap[i]) { [heap[p], heap[i]] = [heap[i], heap[p]]; i = p; } else break;
        }
    }
    function pop() {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length) {
            heap[0] = last;
            let i = 0;
            while (true) {
                let l = 2 * i + 1, r = 2 * i + 2, largest = i;
                if (l < heap.length && heap[l] > heap[largest]) largest = l;
                if (r < heap.length && heap[r] > heap[largest]) largest = r;
                if (largest === i) break;
                [heap[i], heap[largest]] = [heap[largest], heap[i]];
                i = largest;
            }
        }
        return top;
    }
    const res = [];
    for (const [x, y] of queries) {
        const d = Math.abs(x) + Math.abs(y);
        if (heap.length < k) {
            push(d);
        } else if (heap[0] > d) {
            pop();
            push(d);
        }
        res.push(heap.length === k ? heap[0] : -1);
    }
    return res;
};
